export function getCountiesForState(state: string): CountyData[] {
  return US_COUNTIES.filter(c => c.state === state)
}

export function computeTerritoryCenter(counties: CountyData[]): { lat: number; lng: number; radiusMiles: number } {
  if (counties.length === 0) return { lat: 0, lng: 0, radiusMiles: 50 }
  const avgLat = counties.reduce((s, c) => s + c.lat, 0) / counties.length
  const avgLng = counties.reduce((s, c) => s + c.lng, 0) / counties.length
  let maxDist = 0
  counties.forEach(c => {
    const dLat = (c.lat - avgLat) * 69
    const dLng = (c.lng - avgLng) * 55
    const dist = Math.sqrt(dLat * dLat + dLng * dLng)
    if (dist > maxDist) maxDist = dist
  })
  return { lat: Math.round(avgLat * 100) / 100, lng: Math.round(avgLng * 100) / 100, radiusMiles: Math.max(30, Math.round(maxDist + 15)) }
}
